// // This register outputs the previous value on the rising edge of the clock when reset is active
module top_module(
                 output logic [7:0] q,
                 input logic [7:0]  d,
                 input logic        clk, rst_n
                 );always_ff @(posedge clk or negedge rst_n)
     if (!rst_n) q <= '0;
     else        q <= d;
endmodule
